/// <summary>
///
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormEventHandler(formStr(InventTableInventoryDimensionGroups), FormEventType::Initialized)]
public static void EcoResProductDetailsExtended_OnInitialized(xFormRun sender, FormEventArgs e)
{
    if(ETGACFParameters::find().EnableDMSIntegration ==NoYes::Yes)
    {
        FormRun formRun = sender as FormRun;

        FormControl productDimCtrl  = formRun.design().controlName("ProductDimensionGroup");
        FormControl storageDimCtrl  = formRun.design().controlName("StorageDimensionGroup");
        FormControl trackingDimCtrl = formRun.design().controlName("TrackingDimensionGroup");

        if (productDimCtrl)
        {
            productDimCtrl.enabled(false);
        }
        if (storageDimCtrl)
        {
            storageDimCtrl.enabled(false);
        }
        if (trackingDimCtrl)
        {
            trackingDimCtrl.enabled(false);
        }
    }
}
